queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?research_scientists a :Research_Scientists .
    ?research_scientists p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?laboratory_technicians a :Laboratory_Technicians .
    ?laboratory_technicians p:name ?name .
    ?laboratory_technicians p:Gender ?gender_f .
    FILTER(STR(?gender_f) = "Female")
    BIND(?name AS ?o0)
  }
}

